```aether:db.ts
import { User, Session } from './types';
import { hashPassword } from './utils/auth';

/**
 * A simple in-memory "database" for users and sessions.
 * In a real application, this would interact with a persistent database (e.g., PostgreSQL, MongoDB).
 */

const users = new Map<string, User>(); // Key: user ID
const sessions = new Map<string, Session>(); // Key: session ID

// --- User Operations ---

/**
 * Finds a user by their email address.
 * @param email The email address to search for.
 * @returns The User object if found, otherwise undefined.
 */
export const findUserByEmail = (email: string): User | undefined => {
  for (const user of users.values()) {
    if (user.email === email) {
      return user;
    }
  }
  return undefined;
};

/**
 * Creates a new user and adds them to the database.
 * @param user The User object to add.
 * @returns The created User object.
 */
export const createUser = (user: User): User => {
  users.set(user.id, user);
  return user;
};

// --- Session Operations ---

/**
 * Finds a session by its ID.
 * @param sessionId The ID of the session to search for.
 * @returns The Session object if found and not expired, otherwise undefined.
 */
export const findSessionById = (sessionId: string): Session | undefined => {
  const session = sessions.get(sessionId);
  if (session && session.expiresAt > new Date()) {
    return session;
  }
  // If session is expired or not found, remove it from the map
  if (session && session.expiresAt <= new Date()) {
    sessions.delete(sessionId);
  }
  return undefined;
};

/**
 * Creates a new session and adds it to the database.
 * @param session The Session object to add.
 * @returns The created Session object.
 */
export const createSession = (session: Session): Session => {
  sessions.set(session.id, session);
  return session;
};

/**
 * Deletes a session by its ID.
 * @param sessionId The ID of the session to delete.
 * @returns True if the session was deleted, false otherwise.
 */
export const deleteSession = (sessionId: string): boolean => {
  return sessions.delete(sessionId);
};

// --- Seed Data (for testing) ---
const seedDatabase = async () => {
  const testUserEmail = 'test@example.com';
  const testUserPassword = 'password123';

  if (!findUserByEmail(testUserEmail)) {
    const passwordHash = await hashPassword(testUserPassword);
    createUser({
      id: crypto.randomUUID(),
      email: testUserEmail,
      passwordHash: passwordHash,
    });
    console.log(`Seeded user: ${testUserEmail} with password: ${testUserPassword}`);
  }
};

seedDatabase();
```

```aether:utils/auth.ts
import bcrypt from 'bcryptjs'; // Using bcryptjs for password hashing

// Recommended salt rounds for bcrypt. Higher is more secure but slower.
const SALT_ROUNDS = 10;

/**
 * Hashes a plaintext password using bcrypt.
 * @param password The plaintext password to hash.
 * @returns A promise that resolves to the hashed password string.
 */
export const hashPassword = async (password: string): Promise<string> => {
  return bcrypt.hash(password, SALT_ROUNDS);
};

/**
 * Compares a plaintext password with a bcrypt hash.
 * @param password The plaintext password.
 * @param hash The bcrypt hash to compare against.
 * @returns A promise that resolves to true if the password matches the hash, false otherwise.
 */
export const comparePassword = async (password: string, hash: string): Promise<boolean> => {
  return bcrypt.compare(password, hash);
};

/**
 * Generates a cryptographically secure random UUID for use as a session ID.
 * @returns A unique session ID string.
 */
export const generateSessionId = (): string => {
  return crypto.randomUUID();
};

/**
 * Creates a Set-Cookie header string for a session cookie.
 * @param sessionId The ID of the session.
 * @param maxAgeSeconds The maximum age of the cookie in seconds.
 * @returns The formatted Set-Cookie header string.
 */
export const createSessionCookie = (sessionId: string, maxAgeSeconds: number): string => {
  // In a production environment, 'Secure' should be true if using HTTPS.
  // 'SameSite=Lax' is a good default for CSRF protection.
  // 'HttpOnly' prevents client-side JavaScript from accessing the cookie.
  return `session_id=${sessionId}; Path=/; Max-Age=${maxAgeSeconds}; HttpOnly; SameSite=Lax`;
  // Add 'Secure' if your application is served over HTTPS:
  // return `session_id=${sessionId}; Path=/; Max-Age=${maxAgeSeconds}; HttpOnly; Secure; SameSite=Lax`;
};
```

```aether:routes/auth.ts
import { Hono } from 'hono';
import { findUserByEmail, createSession } from '../db';
import { comparePassword, generateSessionId, createSessionCookie } from '../utils/auth';
import { Session } from '../types';

const auth = new Hono();

// Session expiration time: 7 days
const SESSION_MAX_AGE_SECONDS = 60 * 60 * 24 * 7;

auth.post('/login', async (c) => {
  const { email, password } = await c.req.json();

  if (!email || !password) {
    return c.json({ error: 'Email and password are required' }, 400);
  }

  // 1. Find the user by email
  const user = findUserByEmail(email);
  if (!user) {
    // Use a generic error message to prevent user enumeration
    return c.json({ error: 'Invalid credentials' }, 401);
  }

  // 2. Compare the provided password with the stored hash
  const passwordMatches = await comparePassword(password, user.passwordHash);
  if (!passwordMatches) {
    return c.json({ error: 'Invalid credentials' }, 401);
  }

  // 3. If credentials are valid, create a new session
  const sessionId = generateSessionId();
  const expiresAt = new Date(Date.now() + SESSION_MAX_AGE_SECONDS * 1000);

  const newSession: Session = {
    id: sessionId,
    userId: user.id,
    expiresAt: expiresAt,
  };

  createSession(newSession);

  // 4. Set the session cookie in the response
  c.header('Set-Cookie', createSessionCookie(sessionId, SESSION_MAX_AGE_SECONDS));

  // 5. Return a success response
  return c.json({ message: 'Login successful', userId: user.id }, 200);
});

export default auth;
```

