import { Hono } from 'hono';
import authRoutes from './routes/auth';

const app = new Hono();

// Mount authentication routes
app.route('/auth', authRoutes);

// Basic root route
app.get('/', (c) => {
  return c.text('Welcome to the Aether Login Service!');
});

// Global error handler (optional, but good practice)
app.onError((err, c) => {
  console.error(`${err}`);
  return c.text('Internal Server Error', 500);
});

// Export the Hono app for deployment (e.g., with Node.js or a serverless function)
export default app;

// To run this locally with Node.js:
// 1. Install dependencies: `npm install hono bcryptjs`
// 2. Create a `package.json` with `"type": "module"`
// 3. Add a start script: `"start": "node --loader ts-node/esm server.ts"` (if using ts-node)
//    Or compile to JS and run: `tsc && node dist/server.js`
// 4. Run `npm start`
//
// Example usage with `curl`:
// curl -X POST -H "Content-Type: application/json" -d '{"email": "test@example.com", "password": "password123"}' http://localhost:3000/auth/login -v
//
// You should see a `Set-Cookie` header in the response.
